import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  const [timeLeft, setTimeLeft] = useState(2700); // 45 Minutes
  const [isActive, setIsActive] = useState(false);
  const [sessionFinished, setSessionFinished] = useState(false);
  const [tabWarning, setTabWarning] = useState(false);
  const videoRef = useRef(null);

  // 1. CAMERA LOGIC: Start camera when component loads
  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        alert("Camera access is REQUIRED to start this session. We need to ensure you are studying!");
      }
    }
    startCamera();

    // Cleanup camera on unmount
    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = videoRef.current.srcObject.getTracks();
        tracks.forEach(track => track.stop());
      }
    };
  }, []);

  // 2. TAB SWITCH DETECTION: Stop timer if they leave the tab
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden) {
        setIsActive(false); // Pause the timer
        setTabWarning(true); // Show warning
      } else {
        setTabWarning(false);
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  }, []);

  // 3. TIMER LOGIC
  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0) {
      setSessionFinished(true);
      setIsActive(false);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs < 10 ? '0' : ''}${secs}s`;
  };

  return (
    <div style={{ padding: '20px', textAlign: 'center', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      <div style={{ maxWidth: '800px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '15px' }}>
        
        <h2 style={{ color: '#2c3e50' }}>Day {day}: {state?.topic}</h2>

        {/* PROCTOR CAMERA VIEW */}
        <div style={{ position: 'relative', width: '320px', height: '240px', margin: '20px auto', backgroundColor: '#000', borderRadius: '10px', overflow: 'hidden', border: '4px solid #3498db' }}>
          <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          {!isActive && !sessionFinished && (
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.6)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              Paused
            </div>
          )}
        </div>

        {/* TAB WARNING */}
        {tabWarning && (
          <div style={{ backgroundColor: '#ff4d4d', color: 'white', padding: '10px', borderRadius: '5px', marginBottom: '15px' }}>
            <strong>WARNING:</strong> Timer paused. You must stay on this tab to continue studying!
          </div>
        )}

        <div style={{ fontSize: '60px', fontWeight: 'bold', margin: '20px 0', color: timeLeft === 0 ? '#27ae60' : '#2c3e50' }}>
          {formatTime(timeLeft)}
        </div>

        {!sessionFinished ? (
          <div>
            <p style={{ color: '#7f8c8d' }}>Stay focused! Switching tabs or minimizing the browser stops the clock.</p>
            <button 
              onClick={() => setIsActive(!isActive)}
              style={{ padding: '15px 40px', fontSize: '18px', background: isActive ? '#f39c12' : '#2ecc71', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}
            >
              {isActive ? 'Pause Session' : 'Start Studying Now'}
            </button>
          </div>
        ) : (
          <div style={{ backgroundColor: '#d4edda', padding: '20px', borderRadius: '8px' }}>
            <h3>Knowledge Verification Unlocked</h3>
            <p>You have successfully completed the focus block. Now summarize your findings.</p>
            <textarea style={{ width: '100%', height: '100px', padding: '10px' }} placeholder="What did you learn?" />
            <button 
              onClick={() => { markDayComplete(day); navigate('/dashboard'); }}
              style={{ marginTop: '15px', padding: '10px 20px', background: '#2c3e50', color: 'white', borderRadius: '5px' }}
            >
              Complete Day {day}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
